    "snpAssocBase",
    inherit = jmvcore::Analysis,
    public = list(
        initialize = function(options, data=NULL, datasetId="", analysisId="", revision=0) {
            super$initialize(
                package = "SNPstats",
                name = "snpAssoc",
                version = c(0,2,0),
                options = options,
                results = snpAssocResults$new(options=options),
                data = data,
