#' SNP Association Analysis
#'
#' 
#' @param data [object Object]
#' @param response .
#' @param snps .
#' @param covariates .
#' @param responseType .
#' @param snpAssoc .
#' @param modelCodominant .
#' @param modelDominant .
#' @param modelRecessive .
#' @param modelOverdominant .
#' @param modelLogAdditive .
#' @param ciWidth .
#' @param showAIC .
#' @param snpInteraction .
#' @param interactionType .
#' @param showInteractionTable .
#' @param showInteractionAdjVars .
#' @param showStratByCovariate .
#' @param showStratByGenotype .
#' @param showCrossClassTable .
#' @return A results object containing:
#' \tabular{llllll}{
#'   \code{results$validationMsg} \tab \tab \tab \tab \tab a html \cr
#'   \code{results$snpResults} \tab \tab \tab \tab \tab Per-SNP association results \cr
#' }
#'
#' @export
snpAssoc <- function(
    data,
    response,
    snps,
    covariates = NULL,
    responseType = "auto",
    snpAssoc = TRUE,
    modelCodominant = TRUE,
    modelDominant = FALSE,
    modelRecessive = FALSE,
    modelOverdominant = FALSE,
    modelLogAdditive = FALSE,
    ciWidth = 95,
    showAIC = FALSE,
    snpInteraction = FALSE,
    interactionType = "multiplicative",
    showInteractionTable = TRUE,
    showInteractionAdjVars = FALSE,
    showStratByCovariate = FALSE,
    showStratByGenotype = FALSE,
    showCrossClassTable = FALSE) {

    if ( ! requireNamespace("jmvcore", quietly=TRUE))
        stop("snpAssoc requires jmvcore to be installed (restart may be required)")

    if ( ! missing(response)) response <- jmvcore::resolveQuo(jmvcore::enquo(response))
    if ( ! missing(snps)) snps <- jmvcore::resolveQuo(jmvcore::enquo(snps))
    if ( ! missing(covariates)) covariates <- jmvcore::resolveQuo(jmvcore::enquo(covariates))
    if (missing(data))
        data <- jmvcore::marshalData(
            parent.frame(),
            `if`( ! missing(response), response, NULL),
            `if`( ! missing(snps), snps, NULL),
            `if`( ! missing(covariates), covariates, NULL))


    options <- snpAssocOptions$new(
        response = response,
        snps = snps,
        covariates = covariates,
        responseType = responseType,
        snpAssoc = snpAssoc,
        modelCodominant = modelCodominant,
        modelDominant = modelDominant,
        modelRecessive = modelRecessive,
        modelOverdominant = modelOverdominant,
        modelLogAdditive = modelLogAdditive,
        ciWidth = ciWidth,
        showAIC = showAIC,
        snpInteraction = snpInteraction,
        interactionType = interactionType,
        showInteractionTable = showInteractionTable,
        showInteractionAdjVars = showInteractionAdjVars,
        showStratByCovariate = showStratByCovariate,
        showStratByGenotype = showStratByGenotype,
        showCrossClassTable = showCrossClassTable)

    analysis <- snpAssocClass$new(
        options = options,
        data = data)

    analysis$run()

    analysis$results
}

